256	  const openedGrid = withTile(grid, at, createTile(Terrain.Door, "open"));
257	  const previousOpaque = state.floor.geometry.opaque;
258	  const nextOpaque =
259	    previousOpaque !== null && typeof previousOpaque === "object"
260	      ? ({ ...previousOpaque, ...openedGrid } as SerializableRecord)
261	      : (openedGrid as unknown as SerializableRecord);
262	
263	  return {
264	    state: {
265	      ...state,
